  --radius-sm: 4px;

  font-family: 'Inter', system-ui, -apple-system, sans-serif;
  font-size: 14px;
  line-height: 1.5;
  color: var(--text);
  background: var(--bg);
}

body {
  min-height: 100vh;
  background: var(--bg);
}

#root {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* ── Scrollbar ─── */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--border-light); }

/* ── Header ─── */
.header {
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  padding: 0 24px;
  height: 56px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
}

.header-logo {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 16px;
  font-weight: 600;
  color: var(--text);
}

.header-logo svg {
  color: var(--blue);
}

.health-badge {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 12px;
  color: var(--text-muted);
}

.health-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--gray);
  transition: background 0.3s;
}

.health-dot.ok { background: var(--green); }
.health-dot.error { background: var(--red); }

/* ── Layout ─── */
.layout {
  flex: 1;
  display: grid;
  grid-template-columns: 380px 1fr;
  grid-template-rows: 1fr auto;
  gap: 0;
  min-height: 0;
}

.left-panel {
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  overflow-y: auto;
  max-height: calc(100vh - 56px);
}

.right-panel {
  display: flex;
  flex-direction: column;
  min-height: 0;
  max-height: calc(100vh - 56px);
}

/* ── Upload Panel ─── */
.upload-panel {
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.panel-title {
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-muted);
}

.mode-toggle {
  display: flex;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
}

.mode-btn {
  flex: 1;
  padding: 7px 12px;
  border: none;
  background: transparent;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 13px;
  transition: all 0.15s;
}

.mode-btn.active {
  background: var(--blue);
  color: white;
}

/* ── Drop zone ─── */
.dropzone {
  border: 2px dashed var(--border);
  border-radius: var(--radius);
  padding: 32px 20px;
  text-align: center;
  cursor: pointer;
  transition: all 0.15s;
  color: var(--text-muted);
}

.dropzone:hover, .dropzone.dragover {
  border-color: var(--blue);
  background: rgba(59, 130, 246, 0.05);
  color: var(--text);
}

.dropzone-icon {
  font-size: 32px;
  margin-bottom: 8px;
}

.dropzone p {
  font-size: 13px;
}

.dropzone small {
  font-size: 11px;
  color: var(--text-dim);
  margin-top: 4px;
  display: block;
}

.file-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.file-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 10px;
  background: var(--surface-2);
  border-radius: var(--radius-sm);
  font-size: 12px;
}

.file-item-name {
  flex: 1;
  truncate: ellipsis;
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
}

.file-item-size {
  color: var(--text-dim);
  flex-shrink: 0;
}

.file-remove {
  background: none;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  padding: 0 2px;
  font-size: 14px;
  line-height: 1;
  flex-shrink: 0;
}

.file-remove:hover { color: var(--red); }

/* ── Folder input ─── */
.folder-input-wrap {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.input-label {
  font-size: 12px;
  color: var(--text-muted);
}

.text-input {
  width: 100%;
  padding: 8px 12px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-size: 13px;
  font-family: 'Courier New', monospace;
  outline: none;
  transition: border-color 0.15s;
}

.text-input:focus {
  border-color: var(--blue);
}

.text-input::placeholder {
  color: var(--text-dim);
}

/* ── Prompt ─── */
.prompt-wrap {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

textarea.text-input {
  resize: vertical;
  min-height: 60px;
  font-family: inherit;
}

/* ── Submit button ─── */
.submit-btn {
  width: 100%;
  padding: 10px;
  background: var(--blue);
  color: white;
  border: none;
  border-radius: var(--radius);
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s, opacity 0.15s;
}

.submit-btn:hover:not(:disabled) { background: var(--blue-dim); }
.submit-btn:disabled { opacity: 0.5; cursor: not-allowed; }

.submit-btn.streaming {
  background: var(--gray);
}

/* ── Event Stream ─── */
.event-stream {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
}

.stream-header {
  padding: 14px 20px;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
}

.stream-header h2 {
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-muted);
}

.clear-btn {
  background: none;
  border: 1px solid var(--border);
  color: var(--text-muted);
  padding: 4px 10px;
  border-radius: var(--radius-sm);
  font-size: 11px;
  cursor: pointer;
  transition: all 0.15s;
}

.clear-btn:hover { border-color: var(--border-light); color: var(--text); }

.stream-body {
  flex: 1;
  overflow-y: auto;
  padding: 12px 16px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  min-height: 0;
}

.stream-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-dim);
  font-size: 13px;
  text-align: center;
}

/* ── Event Items ─── */
.event-item {
  display: flex;
  gap: 10px;
  padding: 8px 10px;
  border-radius: var(--radius-sm);
  border-left: 3px solid transparent;
  background: var(--surface);
  font-size: 12px;
  animation: fadeIn 0.15s ease;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(4px); }
  to   { opacity: 1; transform: translateY(0); }
}

.event-item.run_started   { border-color: var(--green);  background: rgba(34,197,94,0.07); }
.event-item.progress      { border-color: var(--gray);   background: var(--surface); }
.event-item.tool_call     { border-color: var(--blue);   background: rgba(59,130,246,0.07); }
.event-item.tool_result   { border-color: var(--purple); background: rgba(167,139,250,0.07); }
.event-item.invoice_result{ border-color: var(--yellow); background: rgba(245,158,11,0.07); }
.event-item.final_result  { border-color: var(--green);  background: rgba(34,197,94,0.12); }
.event-item.error         { border-color: var(--red);    background: rgba(239,68,68,0.10); }

.event-tag {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: 1px 6px;
  border-radius: 3px;
  white-space: nowrap;
  flex-shrink: 0;
  align-self: flex-start;
  margin-top: 1px;
}

.event-tag.run_started    { background: rgba(34,197,94,0.2);   color: var(--green); }
.event-tag.progress       { background: rgba(100,116,139,0.2); color: var(--gray); }
.event-tag.tool_call      { background: rgba(59,130,246,0.2);  color: var(--blue); }
.event-tag.tool_result    { background: rgba(167,139,250,0.2); color: var(--purple); }
.event-tag.invoice_result { background: rgba(245,158,11,0.2);  color: var(--yellow); }
.event-tag.final_result   { background: rgba(34,197,94,0.2);   color: var(--green); }
.event-tag.error          { background: rgba(239,68,68,0.2);   color: var(--red); }

.event-content {
  flex: 1;
  color: var(--text-muted);
  line-height: 1.5;
}

.event-content strong {
  color: var(--text);
  font-weight: 500;
}

.event-meta {
  font-size: 10px;
  color: var(--text-dim);
  margin-top: 2px;
}

/* ── Results Panel ─── */
.results-panel {
  border-top: 1px solid var(--border);
  background: var(--surface);
  overflow: hidden;
  transition: max-height 0.3s ease;
}

.results-panel.hidden { max-height: 0; }
.results-panel.visible { max-height: 60vh; }

.results-inner {
  max-height: 60vh;
  overflow-y: auto;
  padding: 20px;
}

.results-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 12px;
  margin-bottom: 20px;
}

.stat-card {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
}

.stat-label {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-dim);
  margin-bottom: 4px;
}

.stat-value {
  font-size: 22px;
  font-weight: 700;
  color: var(--text);
}

.stat-value.green { color: var(--green); }

.category-list {
  margin-top: 8px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.category-row {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
  color: var(--text-muted);
}

/* ── Invoice Table ─── */
.section-title {
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-muted);
  margin-bottom: 10px;
}

.invoice-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
}

.invoice-table th {
  text-align: left;
  padding: 6px 10px;
  background: var(--bg);
  border-bottom: 1px solid var(--border);
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-dim);
}

.invoice-table td {
  padding: 8px 10px;
  border-bottom: 1px solid var(--border);
  color: var(--text-muted);
  vertical-align: top;
}

.invoice-table tr:last-child td { border-bottom: none; }
.invoice-table tr:hover td { background: rgba(255,255,255,0.03); }

.vendor-name { color: var(--text); font-weight: 500; }
.amount { color: var(--green); font-weight: 600; font-variant-numeric: tabular-nums; }
.confidence-bar { display: flex; align-items: center; gap: 6px; }
.conf-track { flex: 1; height: 4px; background: var(--border); border-radius: 2px; }
.conf-fill { height: 100%; border-radius: 2px; background: var(--blue); }
.conf-label { font-size: 10px; color: var(--text-dim); width: 28px; }

.category-badge {
  display: inline-block;
  padding: 2px 7px;
  border-radius: 10px;
  font-size: 10px;
  font-weight: 600;
  background: rgba(59,130,246,0.15);
  color: var(--blue);
}

.notes-text { font-size: 11px; color: var(--text-dim); max-width: 200px; }

/* ── Issues ─── */
.issues-section {
  margin-top: 16px;
}

.issue-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 6px 10px;
  background: rgba(239,68,68,0.08);
  border-left: 3px solid var(--red);
  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--text-muted);
  margin-bottom: 4px;
}

/* ── Spinner ─── */
.spinner {
  width: 14px;
  height: 14px;
  border: 2px solid rgba(255,255,255,0.2);
  border-top-color: white;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
  display: inline-block;
  flex-shrink: 0;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ── Result panel toggle ─── */
.results-toggle {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 20px;
  cursor: pointer;
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  background: var(--surface);
  user-select: none;
  font-size: 13px;
  font-weight: 600;
  color: var(--text);
}

.results-toggle:hover { background: var(--surface-2); }

.toggle-chevron {
  margin-left: auto;
  transition: transform 0.2s;
}

.toggle-chevron.open { transform: rotate(180deg); }

