.event-item.tool_call     { border-color: var(--blue);   background: rgba(59,130,246,0.07); }
.event-item.tool_result   { border-color: var(--purple); background: rgba(167,139,250,0.07); }
.event-item.invoice_result{ border-color: var(--yellow); background: rgba(245,158,11,0.07); }
.event-item.final_result  { border-color: var(--green);  background: rgba(34,197,94,0.12); }
.event-item.error         { border-color: var(--red);    background: rgba(239,68,68,0.10); }

.event-tag {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: 1px 6px;
  border-radius: 3px;
  white-space: nowrap;
  flex-shrink: 0;
  align-self: flex-start;
  margin-top: 1px;
}

.event-tag.run_started    { background: rgba(34,197,94,0.2);   color: var(--green); }
.event-tag.progress       { background: rgba(100,116,139,0.2); color: var(--gray); }
.event-tag.tool_call      { background: rgba(59,130,246,0.2);  color: var(--blue); }
.event-tag.tool_result    { background: rgba(167,139,250,0.2); color: var(--purple); }
.event-tag.invoice_result { background: rgba(245,158,11,0.2);  color: var(--yellow); }
.event-tag.final_result   { background: rgba(34,197,94,0.2);   color: var(--green); }
.event-tag.error          { background: rgba(239,68,68,0.2);   color: var(--red); }

.event-content {
  flex: 1;
  color: var(--text-muted);
  line-height: 1.5;
}

.event-content strong {
  color: var(--text);
  font-weight: 500;
}

.event-meta {
  font-size: 10px;
  color: var(--text-dim);
  margin-top: 2px;
}

/* ── Results Panel ─── */
.results-panel {
  border-top: 1px solid var(--border);
  background: var(--surface);
  overflow: hidden;
  transition: max-height 0.3s ease;
}

.results-panel.hidden { max-height: 0; }
.results-panel.visible { max-height: 60vh; }

.results-inner {
  max-height: 60vh;
  overflow-y: auto;
  padding: 20px;
}

.results-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 12px;
  margin-bottom: 20px;
}

.stat-card {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 14px 16px;
}

.stat-label {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-dim);
  margin-bottom: 4px;
}

.stat-value {
  font-size: 22px;
  font-weight: 700;
  color: var(--text);
}

.stat-value.green { color: var(--green); }

.category-list {
  margin-top: 8px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.category-row {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
  color: var(--text-muted);
}

/* ── Invoice Table ─── */
.section-title {
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-muted);
  margin-bottom: 10px;
}

.invoice-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
}

.invoice-table th {
  text-align: left;
  padding: 6px 10px;
  background: var(--bg);
  border-bottom: 1px solid var(--border);
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-dim);
}

.invoice-table td {
  padding: 8px 10px;
  border-bottom: 1px solid var(--border);
  color: var(--text-muted);
  vertical-align: top;
}

.invoice-table tr:last-child td { border-bottom: none; }
.invoice-table tr:hover td { background: rgba(255,255,255,0.03); }

.vendor-name { color: var(--text); font-weight: 500; }
.amount { color: var(--green); font-weight: 600; font-variant-numeric: tabular-nums; }
.confidence-bar { display: flex; align-items: center; gap: 6px; }
.conf-track { flex: 1; height: 4px; background: var(--border); border-radius: 2px; }
.conf-fill { height: 100%; border-radius: 2px; background: var(--blue); }
.conf-label { font-size: 10px; color: var(--text-dim); width: 28px; }

.category-badge {
  display: inline-block;
  padding: 2px 7px;
  border-radius: 10px;
  font-size: 10px;
  font-weight: 600;
  background: rgba(59,130,246,0.15);
  color: var(--blue);
}

.notes-text { font-size: 11px; color: var(--text-dim); max-width: 200px; }

/* ── Issues ─── */
.issues-section {
  margin-top: 16px;
}

.issue-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 6px 10px;
  background: rgba(239,68,68,0.08);
  border-left: 3px solid var(--red);
  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--text-muted);
  margin-bottom: 4px;
}

/* ── Spinner ─── */
.spinner {
  width: 14px;
  height: 14px;
  border: 2px solid rgba(255,255,255,0.2);
  border-top-color: white;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
  display: inline-block;
  flex-shrink: 0;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ── Result panel toggle ─── */
.results-toggle {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 20px;
  cursor: pointer;
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  background: var(--surface);
  user-select: none;
  font-size: 13px;
  font-weight: 600;
  color: var(--text);
}

.results-toggle:hover { background: var(--surface-2); }

.toggle-chevron {
  margin-left: auto;
  transition: transform 0.2s;
}

.toggle-chevron.open { transform: rotate(180deg); }

