import { useRef, useState, DragEvent, ChangeEvent } from 'react'
import { InputMode, StreamState } from '../types'

interface Props {
  mode: InputMode
  onModeChange: (m: InputMode) => void
  files: File[]
  onFilesChange: (files: File[]) => void
  folderPath: string
  onFolderChange: (p: string) => void
  prompt: string
  onPromptChange: (p: string) => void
  onSubmit: () => void
  streamState: StreamState
}

function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`
}

export default function UploadPanel({
  mode, onModeChange,
  files, onFilesChange,
  folderPath, onFolderChange,
  prompt, onPromptChange,
  onSubmit, streamState,
}: Props) {
  const [dragover, setDragover] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)

  const addFiles = (incoming: FileList | null) => {
    if (!incoming) return
    const imgs = Array.from(incoming).filter(f =>
      f.type.startsWith('image/') || /\.(png|jpg|jpeg|webp|gif)$/i.test(f.name)
    )
    onFilesChange([...files, ...imgs])
  }

  const handleDrop = (e: DragEvent) => {
    e.preventDefault()
    setDragover(false)
    addFiles(e.dataTransfer.files)
  }

  const removeFile = (i: number) => {
    onFilesChange(files.filter((_, idx) => idx !== i))
  }

  const canSubmit = streamState !== 'streaming' && (
    mode === 'files' ? files.length > 0 : folderPath.trim().length > 0
  )

  return (
    <div className="upload-panel">
      <p className="panel-title">Input</p>

      <div className="mode-toggle">
        <button
          className={`mode-btn ${mode === 'files' ? 'active' : ''}`}
          onClick={() => onModeChange('files')}
        >
          Upload Files
        </button>
        <button
          className={`mode-btn ${mode === 'folder' ? 'active' : ''}`}
          onClick={() => onModeChange('folder')}
        >
          Folder Path
        </button>
      </div>

      {mode === 'files' ? (
        <>
          <div
            className={`dropzone ${dragover ? 'dragover' : ''}`}
            onDragOver={e => { e.preventDefault(); setDragover(true) }}
            onDragLeave={() => setDragover(false)}
            onDrop={handleDrop}
            onClick={() => fileInputRef.current?.click()}
          >
            <div className="dropzone-icon">🧾</div>
            <p>Drop invoice images here</p>
            <small>PNG, JPG, WEBP, GIF — click to browse</small>
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              multiple
              style={{ display: 'none' }}
              onChange={(e: ChangeEvent<HTMLInputElement>) => addFiles(e.target.files)}
            />
          </div>

          {files.length > 0 && (
            <div className="file-list">
              {files.map((f, i) => (
                <div key={i} className="file-item">
                  <span>🖼️</span>
                  <span className="file-item-name">{f.name}</span>
                  <span className="file-item-size">{formatSize(f.size)}</span>
                  <button className="file-remove" onClick={() => removeFile(i)}>✕</button>
                </div>
              ))}
            </div>
          )}
        </>
      ) : (
        <div className="folder-input-wrap">
          <span className="input-label">Absolute folder path containing invoice images</span>
          <input
            type="text"
            className="text-input"
            placeholder="/path/to/invoices"
            value={folderPath}
            onChange={e => onFolderChange(e.target.value)}
          />
        </div>
      )}

      <div className="prompt-wrap">
        <span className="input-label">Optional prompt / instructions</span>
        <textarea
          className="text-input"
          placeholder="e.g. flag invoices over $500, conservative categorization…"
          value={prompt}
          onChange={e => onPromptChange(e.target.value)}
        />
      </div>

      <button
        className={`submit-btn ${streamState === 'streaming' ? 'streaming' : ''}`}
        disabled={!canSubmit}
        onClick={onSubmit}
      >
        {streamState === 'streaming'
          ? <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
              <span className="spinner" /> Processing…
            </span>
          : 'Process Invoices'}
      </button>
    </div>
  )
}

