import { useEffect, useRef } from 'react'
import {
  SSEEvent, RunStartedEvent, ProgressEvent,
  ToolCallEvent, ToolResultEvent, InvoiceResultEvent,
  FinalResultEvent, ErrorEvent,
} from '../types'

interface Props {
  events: SSEEvent[]
  onClear: () => void
}

function renderContent(ev: SSEEvent): { primary: string; meta?: string } {
  switch (ev.event) {
    case 'run_started': {
      const e = ev as RunStartedEvent
      return {
        primary: `Run <strong>${e.run_id.slice(0, 8)}…</strong> started — processing <strong>${e.invoice_count}</strong> invoice${e.invoice_count !== 1 ? 's' : ''}`,
        meta: `${new Date(e.timestamp).toLocaleTimeString()} • mock_mode: ${e.mock_mode}`,
      }
    }
    case 'progress': {
      const e = ev as ProgressEvent
      return {
        primary: e.message || e.step,
        meta: e.total > 0 ? `${e.current}/${e.total}` : e.step,
      }
    }
    case 'tool_call': {
      const e = ev as ToolCallEvent
      return {
        primary: `Calling <strong>${e.tool}</strong>`,
        meta: e.input_summary,
      }
    }
    case 'tool_result': {
      const e = ev as ToolResultEvent
      return {
        primary: `<strong>${e.tool}</strong> completed in <strong>${e.duration_ms} ms</strong>`,
        meta: e.output_summary,
      }
    }
    case 'invoice_result': {
      const e = ev as InvoiceResultEvent
      return {
        primary: `<strong>${e.data.vendor}</strong> — $${e.data.total_usd.toFixed(2)} — ${e.data.category}`,
        meta: `${e.filename} • confidence ${(e.data.confidence * 100).toFixed(0)}%`,
      }
    }
    case 'final_result': {
      const e = ev as FinalResultEvent
      return {
        primary: `Done — <strong>${e.summary.invoice_count}</strong> invoices totalling <strong>$${e.summary.total_spend.toFixed(2)}</strong>`,
        meta: e.issues.length > 0 ? `${e.issues.length} issue(s)` : 'No issues',
      }
    }
    case 'error': {
      const e = ev as ErrorEvent
      return {
        primary: e.message,
        meta: `step: ${e.step} • recoverable: ${e.recoverable}`,
      }
    }
    default:
      return { primary: JSON.stringify(ev) }
  }
}

const TAG_LABELS: Record<string, string> = {
  run_started:    'START',
  progress:       'PROG',
  tool_call:      'CALL',
  tool_result:    'RESULT',
  invoice_result: 'INVOICE',
  final_result:   'FINAL',
  error:          'ERROR',
}

export default function EventStream({ events, onClear }: Props) {
  const bottomRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [events.length])

  return (
    <div className="event-stream">
      <div className="stream-header">
        <h2>Event Stream</h2>
        {events.length > 0 && (
          <button className="clear-btn" onClick={onClear}>Clear</button>
        )}
      </div>

      <div className="stream-body">
        {events.length === 0 ? (
          <div className="stream-empty">
            <div>
              <div style={{ fontSize: '32px', marginBottom: '8px' }}>📡</div>
              <div>SSE events will appear here as they stream in</div>
            </div>
          </div>
        ) : (
          events.map((ev, i) => {
            const { primary, meta } = renderContent(ev)
            return (
              <div key={i} className={`event-item ${ev.event}`}>
                <span className={`event-tag ${ev.event}`}>
                  {TAG_LABELS[ev.event] ?? ev.event}
                </span>
                <div className="event-content">
                  <div dangerouslySetInnerHTML={{ __html: primary }} />
                  {meta && <div className="event-meta">{meta}</div>}
                </div>
              </div>
            )
          })
        )}
        <div ref={bottomRef} />
      </div>
    </div>
  )
}

